public class HighestSharedDivisorCalculator {

    /**
     * Computes the greatest common divisor (GCD) of two integers.
     * @param a First integer
     * @param b Second integer
     * @return The GCD of a and b
     */
    public static int gcd(int a, int b) {
        while (b != 0) {
            int temp = b;
            b = a % b;
            a = temp;
        }
        return a;
    }

    /**
     * Computes the highest shared divisor of a set of integers.
     * @param numbers An array of integers
     * @return The highest shared divisor of all numbers in the array
     */
    public static int highestSharedDivisor(int[] numbers) {
        if (numbers.length == 0) {
            throw new IllegalArgumentException("Cannot compute GCD of an empty array.");
        }

        int currentDivisor = numbers[0];
        for (int i = 1; i < numbers.length; i++) {
            int divisor = gcd(currentDivisor, numbers[i]);
            if (divisor < currentDivisor) {
                currentDivisor = divisor;
            }
        }
        return currentDivisor;
    }

